<template><div class="page-container"><el-card><template #header><span>出库单</span><el-button type="primary" size="small" style="float:right">新建出库单</el-button></template><el-form :inline="true"><el-form-item label="状态"><el-select v-model="f.status" clearable><el-option :value="0" label="待审核"/><el-option :value="1" label="已审核"/><el-option :value="2" label="拣货中"/><el-option :value="3" label="已发货"/></el-select></el-form-item><el-form-item><el-input v-model="f.search" placeholder="单据号" clearable style="width:200px"/></el-form-item><el-form-item><el-button type="primary" @click="search">查询</el-button></el-form-item></el-form><el-table :data="list" border stripe v-loading="loading"><el-table-column prop="order_no" label="单据号" width="150"/><el-table-column prop="source_type" label="来源" width="100"/><el-table-column prop="wave_no" label="波次号" width="100"/><el-table-column prop="status" label="状态" width="80"/><el-table-column prop="creator" label="创建人" width="100"/><el-table-column prop="created_at" label="创建时间" width="160"/><el-table-column label="操作" width="150"><template #default="{ row }"><el-button size="small" @click="handleShip(r)">发货</el-button></template></el-table-column></el-table><el-pagination v-model:current-page="p.page" layout="total,prev,pager,next" :total="p.total" @current-change="load"/></el-card></div></template>
<script setup>import { ref, reactive, onMounted } from 'vue'; import { deliveryApi } from '@/api/wms'; import { ElMessage } from 'element-plus'
const f = reactive({ status: '', search: '' }); const list = ref([]); const loading = ref(false); const p = reactive({ page: 1, total: 0 })
async function load() { loading.value = true; try { const data = await deliveryApi.list({ ...f, page: p.page }); list.value = data?.results || data || []; p.total = data?.count || 0 } catch { } finally { loading.value = false } }
function search() { p.page = 1; load() }
function handleShip(r) { ElMessage.info(`发货: ${r.order_no}`) }
onMounted(load)
</script>
